INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$GPS Time Clock$q$, $q$Employees clock in and out from their phone with GPS location capture and optional geofenced job sites, giving managers verified attendance and location data for payroll.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Employee Scheduling$q$, $q$A drag-and-drop shift builder lets managers assign shifts, publish schedules, handle shift swaps and open-shift claims, and notify staff automatically of changes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Task Management$q$, $q$Managers can assign one-off or recurring tasks with due dates and instructions, and track completion status across the team in real time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Digital Forms & Checklists$q$, $q$Customizable digital forms replace paper checklists for safety inspections, incident reports, and daily job sign-offs, with support for photos and required fields.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Company Chat & Updates Feed$q$, $q$An in-app chat and a company-wide updates feed keep dispersed teams informed, with read-receipt tracking so managers know who has seen a message.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Employee Directory$q$, $q$A searchable, centralized directory of employee contact details and roles, so staff can find and reach the right coworker without needing personal phone numbers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Onboarding & Document Management$q$, $q$New hires can complete onboarding checklists and sign HR documents electronically, with all files stored securely and accessible from the mobile app.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Training & Courses$q$, $q$An in-app course builder supports onboarding training, skills development, and compliance certifications, with quizzes to confirm employee understanding.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Time Off Management$q$, $q$Employees can submit time-off requests from the app, and managers can approve or deny them against configurable policies and balances.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Payroll Integration$q$, $q$Timesheet data from the time clock can be exported or synced to payroll providers, reducing manual re-entry of hours worked.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$A genuinely usable free plan for teams of up to 10 people, not just a stripped-down trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Combines time tracking, scheduling, communication, and HR in one platform instead of several disconnected tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Purpose-built for deskless and field-based workforces rather than adapted from office-first software$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Mobile apps are full-featured for employees, not a limited companion to a desktop product$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Modular hub-based pricing lets a business pay only for the functionality it actually needs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Per-user add-on fees on top of the base plan price can add up for larger teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$More advanced capabilities, such as API access, SSO, and unlimited geofenced sites, are reserved for higher tiers or Enterprise$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Managing three separate hubs can feel like a lot to configure and learn at first$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Task management is lighter than dedicated project management software with dependencies or Gantt-style planning$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Reporting and analytics customization is more limited than what a specialized BI tool or full HRIS platform offers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Does Connecteam have a free plan?$q$, $q$Yes. The Small Business plan is free for up to 10 users and includes access to the Operations, Communications, and HR & Skills hubs.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$What is Connecteam mainly used for?$q$, $q$It's used to manage hourly and field-based teams: tracking time and location, building shift schedules, assigning tasks, sharing company updates, and handling onboarding and HR paperwork.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Does Connecteam integrate with payroll software?$q$, $q$Yes, timesheet data can be exported or connected to common payroll providers to streamline paying hourly employees based on tracked hours.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Is Connecteam available on mobile devices?$q$, $q$Yes, Connecteam has iOS and Android apps for employees and managers, alongside a web dashboard primarily used for administration and reporting.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$How does Connecteam pricing work?$q$, $q$Each hub (Operations, Communications, HR & Skills) has its own tiers — Basic, Advanced, and Expert — priced with a base monthly fee for the first set of users plus a per-additional-user fee, billed monthly or annually. Enterprise pricing is custom.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Job-site time tracking for construction crews$q$, $q$Construction companies use GPS clock-in/out and geofenced job sites to verify where and when crew members worked across multiple active sites, alongside digital safety checklists.$q$, $q$Construction and field service companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Multi-location shift scheduling for retail and restaurants$q$, $q$Retail chains and restaurant groups build and publish shift schedules across several locations, letting staff view schedules, request swaps, and get notified of last-minute changes from their phone.$q$, $q$Retail, restaurant, and hospitality operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Coordinating dispersed caregivers in home healthcare$q$, $q$Home healthcare and home care agencies use scheduling, time tracking, and secure document storage to coordinate caregivers visiting different client locations while keeping certifications and compliance paperwork organized.$q$, $q$Home healthcare and home care agencies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Managing hourly staff across cleaning and janitorial contracts$q$, $q$Cleaning and janitorial companies with hourly staff spread across many client sites use task lists, digital inspection forms, and company-wide updates to keep quality consistent and staff informed.$q$, $q$Cleaning and janitorial services companies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Small Business (Free)$q$, $q$$0$q$, $q$Free$q$, $q$["Up to 10 users","Access to Operations, Communications, and HR & Skills hubs","GPS time clock and basic scheduling","Company chat and updates feed","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Basic$q$, $q$From about $29/month billed annually (about $35/month billed monthly), plus a per-user fee$q$, $q$Monthly or annual$q$, $q$["Covers the first 30 users per hub","Real-time GPS time clock and clock-in/out","Unlimited job and shift tracking","Basic employee scheduling","Company chat and unlimited messaging"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Advanced$q$, $q$From about $49/month billed annually (about $59/month billed monthly), plus a per-user fee$q$, $q$Monthly or annual$q$, $q$["Full time clock customization and auto clock-out","Multiple geofenced job sites","Advanced scheduling filters and templates","Scheduled messages and live polls","Time-off policies and course insights"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Expert$q$, $q$From about $99/month billed annually (about $119/month billed monthly), plus a per-user fee$q$, $q$Monthly or annual$q$, $q$["Unlimited geofenced job sites","Auto-assigned shifts","API access","Custom publishers and pinned posts","Expanded e-signature and document limits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Connecteam is an all-in-one workforce management platform built specifically for organizations with deskless, hourly, or field-based employees — the people who don't sit at a computer all day. Rather than bolting together separate apps for time tracking, scheduling, communication, and HR, Connecteam packages these functions into three connected modules, called hubs, that share the same employee directory and mobile app.$q$, $q$The three hubs are the Operations Hub (time clock, GPS tracking, scheduling, task management, and digital forms), the Communications Hub (company chat, an internal news feed, and employee surveys), and the HR & Skills Hub (onboarding, document storage and e-signatures, training courses, and time-off management). Businesses can subscribe to just one hub or combine all three, and each hub has its own tier structure.$q$, $q$This modular approach sets Connecteam apart from single-purpose tools like a dedicated time clock app or a standalone scheduling tool: instead of employees juggling multiple logins, everything from clocking in to reading a company announcement to requesting time off happens inside one mobile app. For managers, it centralizes oversight of a distributed, non-desk workforce that would otherwise be difficult to track from a single system.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$who-its-for$q$, $q$Who Connecteam Is For$q$, 2, ARRAY[$q$Connecteam is built for managers overseeing hourly or field-based teams — construction crews, retail and restaurant staff, home healthcare and cleaning teams, security guards, and other field service workers. These are industries where employees rarely sit at a desk, don't have a company email address, and need updates, schedules, and forms delivered straight to a personal phone.$q$, $q$Small businesses can start free — the Small Business plan covers up to 10 users across every hub — which makes Connecteam approachable for owner-operators and small crews before they commit to a paid tier. Mid-size and larger organizations with dozens or hundreds of hourly workers across multiple job sites or store locations are typically where the paid Operations, Communications, and HR & Skills hubs earn their cost, since scheduling and time-tracking complexity grows with headcount and site count.$q$, $q$Operations managers, HR coordinators, and franchise or multi-location owners are the most common day-to-day users. They rely on Connecteam to build shift schedules, approve time-off requests, push out safety checklists, and keep a geographically scattered staff informed — jobs that would otherwise mean juggling spreadsheets, group texts, and paper forms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations made up mostly of desk-based knowledge workers — software teams, marketing agencies, or professional services firms where everyone already has a company email and a laptop — generally get less value from Connecteam. Tools built around Slack-style communication, calendar integrations, and project boards are usually a better fit for that kind of work.$q$, $q$Companies that need deep project management capabilities — Gantt charts, resource leveling, dependency tracking, or complex multi-project portfolios — will find Connecteam's task management lighter than dedicated PM software like Asana or monday.com. Similarly, organizations with complex multi-country payroll or compliance requirements may need a specialized HRIS or payroll provider alongside or instead of Connecteam's HR tools.$q$, $q$Very small teams that only need one function, such as a free scheduling app or a bare-bones time clock, may find the full hub structure more than they need, and the per-user add-on fees on paid tiers can make Connecteam pricier than a single-purpose alternative once a team grows past the free plan's 10-user cap.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The Operations Hub covers real-time GPS time tracking with clock-in/clock-out, geofenced job sites, employee scheduling with drag-and-drop shift building and shift swapping, task management for recurring or one-off jobs, and customizable digital forms and checklists that replace paper-based inspections, safety checks, and incident reports.$q$, $q$The Communications Hub centers on an in-app company chat, a social-media-style updates feed for announcements, a searchable employee directory, and tools like surveys, polls, and suggestion boxes for gathering employee feedback. Updates can be scheduled, targeted to specific teams, and tracked for read receipts, giving managers visibility into whether communications actually reached the field.$q$, $q$The HR & Skills Hub handles onboarding checklists, secure document storage with e-signature requests, time-off request and approval workflows with customizable policies, and an in-app training and course builder for skills tracking and compliance certifications. A recognition module lets managers award badges and celebrate milestones like work anniversaries and birthdays.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$connecteam-experience$q$, $q$The Connecteam Experience$q$, 2, ARRAY[$q$Getting started typically means an administrator setting up the company account on the web dashboard, importing or inviting employees, and choosing which hubs to activate. Templates for schedules, forms, and onboarding checklists cut down on building everything from a blank page, and the initial setup is aimed at non-technical managers rather than IT staff.$q$, $q$For frontline employees, day-to-day use is almost entirely through the mobile app: clocking in with GPS, checking the week's schedule, reading updates from management, and completing an assigned form or course. Managers spend more time on the web dashboard, where scheduling, reporting, and hub configuration are easier to manage on a larger screen.$q$, $q$Overall, the experience favors breadth over depth — Connecteam trades the sharper edges of specialized tools for a single system that a non-desk workforce can actually use consistently, since employees only need to learn one app rather than several. Teams that value that consolidation tend to get the most out of it; teams wanting the deepest version of any single feature may still want to pair it with a specialist tool.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Email Campaign Builder$q$, $q$A drag-and-drop editor with hundreds of pre-built templates for creating newsletters, promotions, and announcements without design experience.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Marketing Automation$q$, $q$Trigger-based automated paths for welcome series, re-engagement, and abandoned-cart follow-up, built from pre-set journeys rather than a fully custom flow builder.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$List Segmentation & Tagging$q$, $q$Organize contacts by tags, purchase history, or engagement so campaigns can be targeted to specific subsets of a list.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$E-commerce Marketing$q$, $q$Shopify and WooCommerce integrations that power abandoned-cart emails, product recommendation blocks, and purchase-based segmentation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$SMS Marketing$q$, $q$Text-message campaigns that run alongside email, aimed at time-sensitive promotions and reminders.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Social Media & Ad Manager$q$, $q$Schedule social posts and manage Facebook, Instagram, and Google ad campaigns from the same dashboard used for email.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Event Marketing$q$, $q$Registration pages, ticketing details, and automated reminders for webinars, fundraisers, and in-person events.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Surveys & Polls$q$, $q$Built-in forms for collecting audience feedback without needing a separate survey tool.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Reporting & A/B Testing$q$, $q$Dashboards tracking opens, clicks, and bounces, plus split testing of subject lines and content to compare performance.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$AI Content Generator$q$, $q$An AI writing tool, available on paid plans, that drafts subject lines, email copy, and social captions from a short text prompt.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$A large, long-refined template library and guided editor make it easy for non-designers to produce professional-looking campaigns quickly$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Support options are broader than many competitors, including phone support, live chat, a community forum, and coaching webinars$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Built-in e-commerce features such as abandoned-cart emails and product blocks connect directly to Shopify and WooCommerce stores$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Bundled channels beyond email, including SMS, social posting, event registration, and ad management, reduce the need for separate point tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Nonprofit discount pricing and a straightforward three-tier plan structure make budgeting predictable for small teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$There is no permanent free plan, only a time-limited free trial, so ongoing use always carries a monthly cost$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Pricing scales steeply with contact list size, which can become expensive quickly for growing lists$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$The marketing automation builder is less flexible than dedicated automation platforms like ActiveCampaign or HubSpot for complex, multi-branch journeys$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$An account can only operate in one interface and content language at a time, limiting native multilingual campaign workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$More advanced capabilities, such as SEO tools, dynamic content, and the Ad Manager, are reserved for the higher-priced Premium tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Does Constant Contact have a free plan?$q$, $q$No. Constant Contact offers a time-limited free trial rather than an ongoing free plan; after the trial, continued use requires a paid subscription starting with the Lite tier.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$What does Constant Contact integrate with?$q$, $q$It connects with e-commerce platforms like Shopify and WooCommerce, website builders such as Wix, CRMs including Salesforce, social networks, and other apps through its marketplace and public API.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Can I send SMS or text messages through Constant Contact?$q$, $q$Yes, SMS marketing is available as part of the platform for sending text-based campaigns and reminders alongside email.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Is Constant Contact a good fit for e-commerce businesses?$q$, $q$It can work well for smaller online stores thanks to abandoned-cart emails, product recommendation blocks, and purchase-based segmentation, though larger commerce operations may want a more commerce-native platform.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$What is the difference between the Lite, Standard, and Premium plans?$q$, $q$Lite covers basic email campaigns and reporting; Standard adds automation paths, A/B testing, and segmentation; Premium adds dynamic content, more advanced automation, SEO tools, and Ad Manager access.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Small business newsletters and promotions$q$, $q$Regularly scheduled newsletters, sales announcements, and seasonal promotions built from templates without needing a designer or developer.$q$, $q$Local retailers and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Nonprofit fundraising and outreach$q$, $q$Fundraising appeals, volunteer updates, and membership communications supported by discounted nonprofit pricing and event registration tools.$q$, $q$Nonprofits and community organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$E-commerce lifecycle emails$q$, $q$Abandoned-cart recovery, post-purchase follow-up, and product recommendation emails tied to a connected Shopify or WooCommerce store.$q$, $q$Small online store owners$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Event and webinar promotion$q$, $q$Registration pages, reminder sequences, and post-event follow-up for workshops, fundraisers, and community gatherings.$q$, $q$Event organizers and local associations$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Lite$q$, $q$From $12/month$q$, $q$Monthly (500 contacts; discount available for annual billing)$q$, $q$["Drag-and-drop email builder with templates","Basic email campaigns and newsletters","1GB of storage","Core performance tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Standard$q$, $q$From $35/month$q$, $q$Monthly (500 contacts; discount available for annual billing)$q$, $q$["Everything in Lite","A/B testing","List segmentation","Pre-built automation paths","Drill-down reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Premium$q$, $q$From $80/month$q$, $q$Monthly (500 contacts; discount available for annual billing)$q$, $q$["Everything in Standard","Dynamic content and custom automation paths","Advanced segmentation","SEO tools","Ad Manager for Facebook, Instagram, and Google ads"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Constant Contact is an email marketing and marketing automation platform that has served small businesses and nonprofits since it launched in 1995, making it one of the oldest names in the category. Over time it expanded from simple email newsletters into a broader marketing suite that includes automation, e-commerce tools, event registration, and paid advertising management, all built around the idea that a small team without a dedicated marketing department should be able to run professional campaigns without hiring outside help.$q$, $q$The platform is organized around a central contact list and a drag-and-drop campaign builder, with everything else, automation paths, segmentation, reporting, and integrations, layered on top of that core email experience. Constant Contact positions itself as more approachable than enterprise marketing clouds like HubSpot or Marketo, while offering more built-in channels, such as SMS, social posting, and paid ads, than lighter tools aimed purely at email newsletters.$q$, $q$The company has changed hands over the years, moving from an independent public listing to a period under Endurance International Group and later to private ownership, and it remains headquartered in Waltham, Massachusetts. The product is delivered entirely as a web application with companion mobile apps, so there is nothing to install or self-host, and updates roll out continuously rather than through versioned releases.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$who-its-for$q$, $q$Who Constant Contact Is For$q$, 2, ARRAY[$q$Constant Contact is built for small business owners, local retailers, and solo marketers who need to send newsletters, promotions, and announcements regularly but do not have a dedicated email marketing specialist on staff. The template library and guided editor are aimed squarely at people who want a professional-looking result quickly, without needing design or coding skills to get a campaign out the door.$q$, $q$Nonprofits and community organizations are also a core audience: the platform offers discounted nonprofit pricing and includes event registration, membership communication templates, and survey tools that fit fundraising campaigns, volunteer outreach, and donor updates without requiring a separate donor-management system. Membership associations, schools, and local clubs use the same tools to keep newsletters, calendars, and event reminders flowing on a predictable schedule with a small volunteer team rather than paid staff.$q$, $q$E-commerce sellers on Shopify, WooCommerce, or similar platforms who want abandoned-cart emails, product recommendation blocks, and promotional automation without adopting a full commerce-focused marketing suite will find the integrations useful, especially if email remains their primary channel alongside lighter social and ad management needs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Growing companies that need sophisticated, multi-branch marketing automation, conditional logic across many touchpoints, lead scoring, and deep CRM synchronization, will likely find Constant Contact's automation builder more limited than dedicated platforms such as ActiveCampaign, Klaviyo, or HubSpot, which are built with more complex customer journeys in mind.$q$, $q$Organizations that regularly send content in more than one language within the same account may also run into friction, since an account operates in a single interface and content language at a time rather than offering native multilingual campaign management or per-segment localization.$q$, $q$Budget-conscious users hoping for a permanently free tier should look elsewhere: Constant Contact offers only a time-limited free trial rather than an ongoing free plan, and monthly cost increases substantially as a contact list grows, which can catch fast-growing lists off guard if it is not budgeted for in advance.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Constant Contact provides a drag-and-drop email builder with a large template library, list segmentation and tagging, and automation paths for common journeys like welcome series, re-engagement, and abandoned-cart follow-up. A/B testing and reporting dashboards covering opens, clicks, bounces, and comparative campaign performance round out the email side of the platform.$q$, $q$Beyond email, the platform bundles SMS marketing, social media post scheduling, and an Ad Manager for running Facebook, Instagram, and Google ads from the same dashboard, so a small team can plan a promotion across channels without switching tools. Event marketing tools handle registration pages, ticketing details, and reminders, and built-in surveys and polls let users collect feedback without a separate survey tool.$q$, $q$E-commerce features, including abandoned-cart emails, product blocks pulled from a connected store, and purchase-based segmentation, integrate with Shopify and WooCommerce. Integrations extend further to CRMs such as Salesforce and hundreds of third-party apps through a marketplace and a public API, so contact data and store activity can flow into campaigns without manual list uploads. An AI content generator, available on paid plans, can draft subject lines, email body copy, and social captions from a short prompt, and the Premium tier adds on-page SEO tools, dynamic content, and more advanced automation branching.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$constant-contact-experience$q$, $q$The Constant Contact Experience$q$, 2, ARRAY[$q$New users are walked through a setup wizard that imports contacts, picks a template, and suggests a first automation, which keeps the early experience from feeling like a blank canvas. The editor itself favors pre-built blocks and layouts over freeform design, which speeds up campaign creation at some cost to fine-grained visual customization for users who want pixel-level control.$q$, $q$Support is one of the more consistent themes in user feedback: Constant Contact offers phone support, live chat, an active community forum, and coaching webinars, which is more extensive than what many competing email tools provide, and matters for users without in-house marketing expertise who need a real person to walk them through a problem.$q$, $q$Mobile apps for iOS and Android let users check campaign performance, manage contacts, and post to social channels on the go, though most campaign building still happens in the full desktop dashboard. Overall the day-to-day experience emphasizes speed and guidance over deep customization, which fits its target audience of busy small-business owners more than marketing teams wanting a highly configurable workflow.$q$]::text[], 4);
