INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca95321e-8259-4037-a292-11f90e6c3856', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Workflows$q$, $q$Multi-step automations that chain prompts, data lookups, and third-party actions into a repeatable process, such as researching a lead and drafting follow-up outreach.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Actions$q$, $q$The individual building blocks inside a workflow, including API calls, AI generation steps, and data transformations, that non-experts can assemble without writing code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Agents$q$, $q$Automated task execution with a layer of decision-making, allowing a workflow to branch or take follow-up steps based on its own output rather than a fixed script.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Tables$q$, $q$A queryable, spreadsheet-like data layer that consolidates leads, enrichment results, and content drafts so workflows have a shared source of data to read from and write to.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Chat$q$, $q$A straightforward prompting interface for one-off writing and research tasks, closest to Copy.ai's original AI copywriting tool experience.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Infobase$q$, $q$A centralized repository of company and product information that workflows and chat can reference to keep generated content accurate and consistent.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Brand Voice$q$, $q$A configurable tone-and-style setting applied across generated outputs to keep content consistent with a company's established voice.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Model-agnostic AI$q$, $q$Support for multiple underlying language models, including OpenAI, Anthropic, Google Gemini, and Perplexity, rather than being locked to a single provider.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Integrations$q$, $q$Native and Zapier-style connections to CRM, sales engagement, and data tools such as Salesforce, HubSpot, Gong, Outreach, and Salesloft.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Templates$q$, $q$A library of pre-built prompts and layouts for common content tasks like blog outlines, ad copy, and social captions, aimed at quick, no-setup results.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Consolidates several go-to-market point tools into a single workflow-driven platform instead of stitching together separate apps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Model-agnostic setup lets teams choose or mix leading AI providers rather than being locked into one$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Extensive integration coverage with common CRM and sales engagement tools reduces manual data handoffs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$A genuinely free, ongoing plan gives light users a way to try core content generation without a paid commitment$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Agents and Tables allow non-technical teams to automate multi-step processes without writing code$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Pricing jumps sharply between the self-serve Chat plan and the Growth-tier workflow automation plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Building and maintaining Workflows and Agents requires more setup effort than a simple prompt-based writing tool$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$The free plan's word allowance is limited enough to suit only very occasional, light content needs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Enterprise pricing is not published, making it harder to budget or compare against competitors up front$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Users who only want straightforward long-form writing assistance may find the platform's automation focus unnecessary for their needs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Is Copy.ai still an AI copywriting tool?$q$, $q$It still includes a Chat interface, templates, and a free plan for content generation, but Copy.ai now describes itself as a GTM AI platform focused on workflow automation for sales, marketing, and operations teams rather than a standalone copywriting product.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Does Copy.ai have a free plan?$q$, $q$Yes. Copy.ai offers an ongoing free plan with a limited monthly word allowance and access to its template library, separate from its paid Chat, Growth, and Enterprise tiers.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Which AI models does Copy.ai use?$q$, $q$Copy.ai is model-agnostic and connects to multiple large language model providers, including OpenAI, Anthropic, Google Gemini, and Perplexity, rather than relying on a single model.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Does Copy.ai integrate with CRM and sales tools?$q$, $q$Yes. It offers native and Zapier-based integrations with tools such as Salesforce, HubSpot, Gong, Outreach, and Salesloft, letting workflows read and write data across a company's existing stack.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Is Copy.ai a good fit for a solo blogger or independent writer?$q$, $q$It can handle light writing tasks through Chat, templates, or the free plan, but its deeper value and pricing are built around teams automating GTM processes, so dedicated writing tools may be a simpler fit for purely individual content work.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Sales prospecting and outreach automation$q$, $q$Building a workflow that researches a lead, drafts personalized outreach copy, and logs the result into a CRM or sales engagement tool.$q$, $q$Sales development and business development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Marketing content production at scale$q$, $q$Using Brand Voice and Infobase alongside templates and workflows to produce on-brand blog, ad, and social content more consistently across a team.$q$, $q$Marketing and content teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Lead and CRM data enrichment$q$, $q$Using Tables and Actions to consolidate, clean, and enrich lead or account data pulled from multiple sources before it reaches a CRM.$q$, $q$Revenue operations and marketing operations specialists$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Quick, one-off AI writing$q$, $q$Using the Chat interface or free plan to draft an email, caption, or landing page snippet without building a full workflow.$q$, $q$Freelancers, solo marketers, and small business owners$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Limited monthly word allowance","Access to the template library","Chat interface for one-off tasks","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Chat$q$, $q$$29/month ($24/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Up to 5 seats","Unlimited words in Chat","Unlimited chat projects","Access to OpenAI, Anthropic, and Gemini models"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Growth$q$, $q$$1,000/month (billed annually at $12,000/year)$q$, $q$Annual$q$, $q$["Up to 75 seats","Workflow automation and Agents","20,000 workflow credits per month","CRM and sales tool integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$Enterprise$q$, $q$Custom$q$, $q$Custom / contact sales$q$, $q$["Guided implementation and onboarding","API access and bulk workflow runs","20+ technology integrations","Dedicated account and support team","SOC 2, GDPR, and SSO support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Copy.ai launched in 2020 as an AI-powered copywriting tool that used large language models to generate blog outlines, ad copy, product descriptions, and social captions from short prompts. Its early templates made it one of the more recognizable AI writer products during the initial wave of generative AI content tools, alongside a handful of other GPT-based writing assistants that appeared around the same time.$q$, $q$Over time, Copy.ai reworked its product around go-to-market operations, describing itself as a GTM AI platform rather than a copywriting tool. The current product organizes work into Workflows, Actions, Agents, and Tables, letting sales, marketing, and revenue operations teams automate multi-step processes instead of generating one piece of copy at a time. That shift mirrors a broader trend among AI writing startups toward workflow automation, as pure text generation became commoditized across many competing tools.$q$, $q$The platform is model-agnostic, connecting to OpenAI, Anthropic, Google Gemini, and Perplexity, and it can be wired into a company's existing stack through native integrations and Zapier-style connections to tools like Salesforce, HubSpot, Gong, Outreach, and Salesloft. A simpler Chat interface and free tier still exist for quick, one-off writing tasks, so the original content-generation use case has not disappeared, it has just become one part of a larger system.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$who-copyai-is-for$q$, $q$Who Copy.ai Is For$q$, 2, ARRAY[$q$Copy.ai's current positioning targets sales, marketing, and operations teams inside mid-market and larger companies that already run several point solutions, a content generator, a sequencer, a data enrichment tool, and want to consolidate that logic into fewer, more automatable workflows.$q$, $q$Revenue operations and marketing ops specialists who are comfortable mapping out a process step by step benefit from Actions, Agents, and Tables, since these let a team codify how it already prospects, qualifies leads, or produces on-brand content, then run that process repeatedly with less manual work. Teams that already rely on a CRM such as Salesforce or HubSpot, or on outreach tools like Outreach, Salesloft, or Gong, get more value out of Copy.ai because those connections let a workflow read and write data without manual exports.$q$, $q$Solo marketers, freelancers, and small businesses that only need occasional help writing captions, emails, or landing page copy can still use the Chat interface or the free plan, and lighter template-driven work remains accessible even though most of Copy.ai's product investment has shifted toward workflow automation for teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Writers and marketers who want a dedicated, low-friction long-form drafting tool, think blog posts, newsletters, or books, may find Copy.ai's workflow-first interface more setup than they need; simpler AI writing assistants built around a single document editor are typically a better fit for that narrower job.$q$, $q$Small teams without a defined GTM process, or without someone willing to build and maintain Workflows and Agents, may not extract much value from the higher tiers; the jump from the self-serve Chat plan to Growth-level automation pricing is significant, and that spend is hard to justify without an existing repeatable process to automate. Companies that need only a handful of Enterprise features, such as bulk workflow runs or guided implementation, may also find it hard to size which plan fits, since detailed Enterprise pricing is only available by contacting sales.$q$, $q$Organizations already committed to point solutions, or to an existing GTM automation platform deeply embedded in their revenue stack, may find migrating processes into Copy.ai's Actions and Tables redundant rather than simplifying, at least until the return on that migration effort is clear.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Workflows are Copy.ai's core building block: they string together prompts, data lookups, and third-party actions into a repeatable process, such as researching a lead, drafting outreach copy, and logging the result back into a CRM, without requiring custom code.$q$, $q$Actions are the individual steps inside a workflow, an API call, an AI generation step, a data transformation, while Agents add a layer of autonomous decision-making so a process can branch or take follow-up steps based on its own output rather than a fixed script. Tables give teams a queryable, spreadsheet-like data layer that a workflow can read from or write to, functioning as the platform's shared data foundation for lead lists, enrichment results, and content drafts alike.$q$, $q$Supporting features round out the platform: Chat offers a simple prompting interface for one-off requests, Infobase centralizes company and product information so generated content stays consistent, and Brand Voice applies a defined tone and style across outputs. Copy.ai also supports multiple LLM providers and lists thousands of possible integrations, along with SOC 2, GDPR, and SSO support for enterprise buyers.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', $q$copyai-experience$q$, $q$The Copy.ai Experience$q$, 2, ARRAY[$q$New users typically start in the Chat interface or with one of the platform's many templates, which mirrors the product's original copywriting-tool feel and gives a fast first result. Moving into Workflows, Actions, and Agents introduces a steeper learning curve, closer to configuring an automation platform than typing a prompt into a text box.$q$, $q$Teams that invest the time to map an existing process into a Workflow tend to describe the payoff as real time savings on repetitive tasks, but that payoff depends on having the internal know-how, or budget for guided onboarding, to build and maintain the automation correctly. Enterprise customers get a dedicated onboarding and support team, guided implementation, and access to bulk workflow runs and API access, which softens that learning curve considerably and helps larger teams standardize workflows across departments rather than leaving each team to build its own.$q$, $q$Self-serve customers on the Free or Chat plans get a lighter-weight version of the experience, usable for quick content generation, but without the deeper automation tooling that Copy.ai now positions as its primary value. The overall experience is best understood as two products in one: an approachable AI writer for quick tasks, and a considerably more complex GTM automation platform underneath it.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c515695-9a2f-4479-901f-6ca785a0e07c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
